// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long dp[N + 1][N + 1] = {0};
        dp[0][0] = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j <= N; j++) {
                if (dp[i][j] == 0) continue;
                if (A[i] != -1) {
                    if (j + 1 == A[i]) {
                        dp[i + 1][A[i]] = (dp[i + 1][A[i]] + dp[i][j]) % MOD;
                    }
                } else {
                    if (j == 0) {
                        for (int k = 1; k <= N; k++) {
                            dp[i + 1][k] = (dp[i + 1][k] + dp[i][j]) % MOD;
                        }
                    } else {
                        dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD;
                        dp[i + 1][1] = (dp[i + 1][1] + dp[i][j]) % MOD;
                    }
                }
            }
        }
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

